#include <stdio.h>
#include <string.h>

/* == EXEMPLE ================================================
 * snprintf: sprintf sûr avec limite de taille
 * =========================================================== */
void example_snprintf(void) {
    char buf[8];
    int ret = snprintf(buf, sizeof(buf), "ABCDEFGHIJ");
    printf("'%s' ret=%d trunc=%s\n", buf, ret, ret >= 8 ? "YES" : "NO");
    /* 'ABCDEFG' ret=10 trunc=YES */
}

